20	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
21	
22	const countByType = (items: Item[]): Map<string, number> => {
23	  const counts = new Map<string, number>();
24	  for (const item of items) {
25	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
26	  }
27	  return counts;
28	};
29	
30	const componentTypeBase = (count: number): number =>
31	  count === 3 ? BLOCK_OF_THREE_BASE : count * COMPONENT_BASE;
32	
33	const mainItemsBase = (items: Item[]): number =>
34	  items
35	    .filter((item) => !isComponent(item))
36	    .reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
37	
38	const componentsBase = (items: Item[]): number => {
39	  const counts = countByType(items.filter(isComponent));
40	  let total = 0;
41	  for (const count of counts.values()) {
42	    total += componentTypeBase(count);
43	  }
44	  return total;
45	};
46	
47	const quote = (step: QuoteStep): QuoteResult => {
48	  const itemsTotal = mainItemsBase(step.items) + componentsBase(step.items);
49	  return { premium: itemsTotal + PROCESSING_FEE };
50	};
51	
52	export const runScenario = (scenario: Scenario): ScenarioResult => ({
53	  results: scenario.steps.map(quote),
54	});
